import ParserDownload from './ParserDownload';
import minimist = require('minimist');
import path = require('path');
import chalk = require('chalk');

export default function() {
    // Get the commandline argument
    let args = minimist(process.argv.slice(2), {
        boolean: ['force32', 'rename', 'verbose'],
        string: ['version', 'url', 'type', 'dir', 'temp'],
        alias: {
            f: 'force32',
            r: 'rename',
            v: 'version',
            u: 'url',
            t: 'type',
            d: 'dir',
            c: 'temp',
            b: 'verbose'
        }
    });

    // Check for package.json settings
    let packageInfo;
    try {
        packageInfo = require(path.join(process.cwd(), 'package'));
    }
    catch(e) {
        // don't care, package.json not required
    }

    if (packageInfo && packageInfo.parser) {
        if (typeof packageInfo.parser === "string") {
            packageInfo.parser = {
                version: packageInfo.parser
            };
        }
        // args always win, package json is default
        args = Object.assign({}, packageInfo.parser, args);
    }

    // Handle the logs in verbose mode
    (args as any).logger = function(message) {
        console.log(chalk.gray('[parser-download]'), message);
    };

    // Handle the download
    const download = new ParserDownload(args);
    download.start()
        .catch((err) => {
            console.log(chalk.red("ERROR: " + err));
            process.exit(1);
        });
};