import fs = require('fs-extra');
import path = require('path');
import nugget = require('nugget');
import extractZip = require('extract-zip');
import envPaths = require('env-paths');
import uuid = require('uuid');

export type ParserCallback = (err?:Error|string) => void;

export interface ParserOptions {
    force32?:boolean;
    rename?:boolean;
    verbose?:boolean;
    version?:string;
    type?:string;
    logger?:Function;
    dir?:string;
    url?:string;
}

/**
 * Download and extract the Jibo NLU parser
 * @class ParserDownload
 */
export default class ParserDownload {

    /**
     * The constructor options
     * @name options
     * @type {Object}
     */
    public options:ParserOptions;

    /**
     * The download URL
     * @name url
     * @type {String}
     */
    public url:string;

    /**
     * The output directory for the parser
     * @name outputDir
     * @type {String}
     */
    public outputDir:string;

    /**
     * The version file to store cache name
     * @name versionPath
     * @type {String}
     */
    public versionPath:string;

    /**
     * The directory path to save zips to.
     * @name cacheDir
     * @type {String}
     */
    public cacheDir:string;

    /**
     * The name of the output cache zip file.
     * @name archiveName
     * @type {String}
     */
    public archiveName:string;

    /**
     * Full path to archive file.
     * @name archivePath
     * @type {String}
     */
    public archivePath:string;

    /**
     * Temporary extraction directory.
     * @name tempDir
     * @type {String}
     */
    public tempDir:string;

    /**
     * The name of the package.
     * @name name
     * @type {String}
     */
    public name:string;

    constructor(optionsOrVersion:ParserOptions|string) {

        let options:ParserOptions;

        // Options can be a version number
        if (typeof optionsOrVersion === "string") {
            options = { version: optionsOrVersion };
        }
        else {
            options = optionsOrVersion;
        }

        // Set the defaults
        options = Object.assign({}, {
            force32: false,
            rename: false,
            verbose: false,
            version: '',
            type: '',
            logger: console.log.bind(console),
            dir: 'parser',
            url: 'https://github.com/jiborobot/jibo-parser/releases/download/'
        }, options || {});

        this.options = options;
    }

    /**
     * Begin the download process.
     * @method start
     */
    public start(): Promise<void> {
        return new Promise<void>((resolve, reject) => {
            const options = this.options;

            if (!options.version) {
                return reject('Must specify a \"version\" to download');
            }

            // Auto-detect version
            if (options.type === 'auto') {
                options.type = process.versions.modules;
            }

            // platform and architecture automatically detected
            let arch = process.arch;

            // Allow overriding of the architecture for windows machines
            // this support that Atom is 32-bit on 64-bit Windows
            if (process.platform === 'win32' && options.force32) {
                arch = 'ia32';
            }

            this.name = 'jibo-nlu-js';
            this.archiveName = this.name + '-v' +
                options.version + '-' +
                process.platform + '-' +
                arch +
                (options.type ? '-' + options.type : '') +
                '.zip';

            this.url = options.url + "v" + options.version + "/" + this.archiveName;
            this.cacheDir = envPaths(this.name).cache;
            this.tempDir = path.join(this.cacheDir, uuid());
            this.outputDir = path.resolve(options.dir);
            this.versionPath = path.join(this.outputDir, this.name + '.txt');
            this.archivePath = path.join(this.cacheDir, this.archiveName);

            if (fs.existsSync(this.versionPath) && fs.readFileSync(this.versionPath, 'utf8') === this.archiveName) {
                this.log("Current target matches downloaded. Skipping.");
                return resolve();
            }

            // Create the cache if it doesn't exit
            if (!fs.existsSync(this.cacheDir)) {
                this.log("Creating global cache directory " + this.cacheDir);
                fs.mkdirsSync(this.cacheDir);
            }

            // Extract but don't do the download
            if (fs.existsSync(this.archivePath)) {
                this.log("Using existing download from cache.");
                this.extract()
                    .then(resolve)
                    .catch(reject);
            }
            else {

                this.download()
                    .then(() => {
                        this.extract()
                            .then(resolve)
                            .catch(reject);
                    })
                    .catch(reject);
            }
        });
    }

    /**
     * Log messages
     * @method log
     * @private
     * @param {string} message
     */
    private log(message:string): void {
        if (this.options.verbose) {
            this.options.logger(message);
        }
    }

    /**
     * Extract the current file.
     * @method extract
     * @private
     */
    private extract():Promise<void> {
        return new Promise<void>((resolve, reject) => {
            this.log("Extracting archive..." + this.archiveName);
            // Create the output and temp folders
            try {
                fs.removeSync(this.outputDir);
                fs.removeSync(this.tempDir);
            }
            catch(e) {
                //don't care
            }
            // Create output folder
            this.log("Creating new target folder: " + this.outputDir);
            fs.mkdirsSync(this.outputDir);
            fs.mkdirsSync(this.tempDir);

            // Extract the file
            extractZip(this.archivePath, { dir: this.tempDir }, (err) => {
                if (err) {
                    return reject(err);
                }
                // Copy the extract output
                fs.copySync(
                    path.join(this.tempDir, this.name),
                    this.outputDir,
                    { clobber: true }
                );

                // Save the file for later
                fs.writeFileSync(this.versionPath, this.archiveName, 'utf8');

                // Remove the temp folder
                fs.removeSync(this.tempDir);

                this.log("Done with extract.");

                if (this.options.rename) {
                    this.rename();
                }
                resolve();
            });
        });
    }

    /**
     * Start the download of the file.
     * @method download
     * @private
     */
    private download():Promise<void> {
        const options = {
            target: this.archiveName,
            dir: this.cacheDir,
            quiet: !('clearLine' in process.stdout),
            verbose: true,
            strictSSL: true,
            resume: true
        };
        return new Promise<void>((resolve, reject) => {
            this.log("Downloading from URL " + this.url);
            nugget(this.url, options, (err) => {
                if (err) {
                    return reject(err);
                }
                this.log("Download complete.");
                resolve();
            });
        });
    }

    /**
     * Get around V8 version red bug in atom by renaming .node file to .jibo
     * @method rename
     * @private
     */
    private rename(): void {
        const parserRoot = path.join(this.outputDir, 'build', 'Release');
        this.log("Renaming 'jsjibonlu.node' to 'jsjibonlu.jibo'");
        fs.renameSync(
            path.join(parserRoot, 'jsjibonlu.node'),
            path.join(parserRoot, 'jsjibonlu.jibo')
        );
    }
}
